trait Greet {
    fn hello(&self);
}

trait Meet {
    fn hello(&self);
}

struct Person;
impl Greet for Person {
    fn hello(&self) { println!("Hi!"); }
}
impl Meet for Person {
    fn hello(&self) { println!("Nice to meet you!"); }
}

fn main() {
    let p = Person;
    p.hello(); // Error: multiple applicable items
}
